const b   = $input.first().json.body || {};
const esc = v => (v || '').toString().replace(/'/g, "''");

const complaintNo     = esc(b.complaintNo || b.complaintId || '').trim();
const remarks         = esc(b.remarks || '');
const newStatus       = esc(b.newStatus || '');
const newEdc          = esc(b.newEdc || '');
const escalationLevel = esc(b.escalationLevel || '');
const reasonForDelay  = esc(b.reasonForDelay || '');
const uid             = parseInt(b.uid || 1);

if (!complaintNo) return [{ json: { error: 'complaintNo required' } }];

// Also fetch current status so we can preserve it on plain updates
const sqlFind = `SELECT c.id, COALESCE(cl.status, 'Open') AS current_status FROM vmm_complaints c LEFT JOIN vmm_complaintlogs cl ON cl.id = (SELECT MAX(id) FROM vmm_complaintlogs WHERE complaintid = c.id) WHERE c.complaintno = '${complaintNo}' AND c.is_deleted = 'No' LIMIT 1`;

return [{ json: { sqlFind, complaintNo, remarks, newStatus, newEdc, escalationLevel, reasonForDelay, uid } }];

const prev = $('LogAct Prepare').first().json;
const row  = $input.first()?.json;

if (!row || !row.id) {
  return [{ json: { found: false, message: `Complaint ${prev.complaintNo} not found`, insertLog: 'SELECT 1', updateSql: 'SELECT 1' } }];
}

const cid = row.id;
const esc = v => (v || '').toString().replace(/'/g, "''");

// Preserve current DB status on plain updates; override for escalate/close
const statusToLog = prev.newStatus || row.current_status || 'Open';
const logRemarks  = prev.remarks || 'Update received';

const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${cid}, '${esc(logRemarks)}', '${esc(statusToLog)}', ${prev.uid}, NOW(), 'No')`;

// Build UPDATE for EDC / escalation level on vmm_vendorescalations
let updateSql = 'SELECT 1';
if (prev.newEdc || prev.escalationLevel) {
  const setParts = [];
  if (prev.newEdc)          setParts.push(`closuredate = '${esc(prev.newEdc)}'`);
  if (prev.escalationLevel) setParts.push(`escalationlevel = '${esc(prev.escalationLevel)}'`);
  // MySQL requires subquery alias to UPDATE from same table
  updateSql = `UPDATE vmm_vendorescalations SET ${setParts.join(', ')} WHERE id = (SELECT max_id FROM (SELECT MAX(id) AS max_id FROM vmm_vendorescalations WHERE complaintid = ${cid}) t)`;
}

return [{ json: { found: true, cid, complaintNo: prev.complaintNo, insertLog, updateSql, statusToLog } }];
